import{_ as t,o as a,c as r,a2 as d}from"./chunks/framework.BWuWLRhz.js";const b=JSON.parse('{"title":"wikimem ADR 索引","description":"","frontmatter":{},"headers":[],"relativePath":"adr/README.md","filePath":"adr/README.md","lastUpdated":1784633569000}'),n={name:"adr/README.md"};function o(i,e,m,l,s,h){return a(),r("div",null,[...e[0]||(e[0]=[d('<h1 id="wikimem-adr-索引" tabindex="-1">wikimem ADR 索引 <a class="header-anchor" href="#wikimem-adr-索引" aria-label="Permalink to &quot;wikimem ADR 索引&quot;">​</a></h1><p>wikimem 的架构决策记录（Architecture Decision Records）。</p><p>创始设计不在本目录：存储层（categories + wiki-links + journal）、检索管线（BM25 + 可选 embedding 融合）以及三条硬约束，来源于宿主项目的 <a href="https://github.com/XnneHangLab/XnneHangLab/blob/dev/docs/adr/0001-llm-mode-memory.md" target="_blank" rel="noreferrer">XnneHangLab ADR-0001</a>（记忆管线）与 <a href="https://github.com/XnneHangLab/XnneHangLab/blob/dev/docs/adr/0002-memu-design-not-dependency.md" target="_blank" rel="noreferrer">XnneHangLab ADR-0002</a>（memU——借鉴设计而非引入依赖）。wikimem 独立成库后，<strong>框架自身的决策记录在这里</strong>；宿主侧的策略决策（意图识别、memorize 策略、情绪、前端）仍记录在 XnneHangLab 的 <code>docs/adr</code>。两边编号各自独立，跨仓引用时注明仓库名。</p><h2 id="继承的硬约束-来自-xnnehanglab-adr-0001" tabindex="-1">继承的硬约束（来自 XnneHangLab ADR-0001） <a class="header-anchor" href="#继承的硬约束-来自-xnnehanglab-adr-0001" aria-label="Permalink to &quot;继承的硬约束（来自 XnneHangLab ADR-0001）&quot;">​</a></h2><ol><li><strong>零基础设施</strong>：没有 embedding 模型、向量库、图数据库时系统必须可用——BM25 兜底，embedding 只是可选增强。</li><li><strong>不为记忆等待 LLM</strong>：retrieve 路径 0 次 LLM 调用；memorize 至多 1 次 LLM 调用、异步、由宿主发起。框架本体零 LLM。</li><li><strong>磁盘上不允许有不可读的真相</strong>：markdown 文件是唯一事实源；一切索引/向量都是可删除、可重建的派生缓存。</li></ol><h2 id="索引" tabindex="-1">索引 <a class="header-anchor" href="#索引" aria-label="Permalink to &quot;索引&quot;">​</a></h2><table tabindex="0"><thead><tr><th>编号</th><th>标题</th><th>状态</th></tr></thead><tbody><tr><td><a href="./0001-diary-store.html">0001</a></td><td>日记原语 — 事件流与状态层分离</td><td>Proposed</td></tr><tr><td><a href="./0002-time-range-retrieval.html">0002</a></td><td>时间检索 — time_range 门控 + 正则快通道，不做第三路融合</td><td>Proposed</td></tr><tr><td><a href="./0003-vectors-cache-metadata.html">0003</a></td><td>向量缓存记录 model/dim — 失配警告并降级，而非报错重建</td><td>Proposed</td></tr><tr><td><a href="./0004-api-contract-thin-shells.html">0004</a></td><td>接口契约 — Python API 是契约，CLI 与 serve 都是薄壳</td><td>Proposed</td></tr></tbody></table><blockquote><p>0001 / 0002 的完整设计讨论（三种时间融合方案的对比分析）见博客《RRF vs Hybrid Search》（nyakku.moe，撰写中）。</p></blockquote>',8)])])}const g=t(n,[["render",o]]);export{b as __pageData,g as default};
